/**
 * API Service - Handles all API calls to the backend
 */

import axios from 'axios';

// Backend API base URL
const API_BASE_URL = 'http://localhost:8000/api';

// Create axios instance with default config
const api = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
  },
  timeout: 10000, // 10 seconds timeout
});

// Request interceptor - runs before every request
api.interceptors.request.use(
  (config) => {
    console.log(`🚀 API Request: ${config.method?.toUpperCase()} ${config.url}`);
    return config;
  },
  (error) => {
    console.error('❌ Request Error:', error);
    return Promise.reject(error);
  }
);

// Response interceptor - runs after every response
api.interceptors.response.use(
  (response) => {
    console.log(`✅ API Response: ${response.status} ${response.config.url}`);
    return response;
  },
  (error) => {
    console.error('❌ API Error:', error.response?.data || error.message);
    return Promise.reject(error);
  }
);

// ==================== Employee APIs ====================
export const employeeAPI = {
  /**
   * Get all employees with pagination
   * @param {number} page - Page number
   * @param {number} pageSize - Items per page
   * @param {string} sortBy - Field to sort by
   * @param {string} sortOrder - Sort order (asc/desc)
   */
  getAll: (page = 1, pageSize = 10, sortBy = 'EmployeeID', sortOrder = 'asc') => {
    return api.get('/employees', {
      params: {
        page,
        page_size: pageSize,
        sort_by: sortBy,
        sort_order: sortOrder,
      },
    });
  },

  /**
   * Search employees with filters
   * @param {object} searchParams - Search parameters
   * @param {number} page - Page number
   * @param {number} pageSize - Items per page
   */
  search: (searchParams = {}, page = 1, pageSize = 10) => {
    return api.post('/employees/search', searchParams, {
      params: {
        page,
        page_size: pageSize,
      },
    });
  },

  /**
   * Get single employee by ID
   * @param {number} id - Employee ID
   */
  getById: (id) => {
    return api.get(`/employees/${id}`);
  },

  /**
   * Create new employee
   * @param {object} employeeData - Employee data
   */
  create: (employeeData) => {
    return api.post('/employees', employeeData);
  },

  /**
   * Update existing employee
   * @param {number} id - Employee ID
   * @param {object} employeeData - Updated employee data
   */
  update: (id, employeeData) => {
    return api.put(`/employees/${id}`, employeeData);
  },

  /**
   * Delete employee
   * @param {number} id - Employee ID
   * @param {boolean} force - Force delete
   */
  delete: (id, force = false) => {
    return api.delete(`/employees/${id}`, {
      params: { force },
    });
  },

  /**
   * Get all departments
   */
  getDepartments: () => {
    return api.get('/employees/departments');
  },

  /**
   * Get all positions
   */
  getPositions: () => {
    return api.get('/employees/positions');
  },
};

// ==================== Payroll APIs ====================
export const payrollAPI = {
  /**
   * Get salary records
   * @param {number} employeeId - Filter by employee ID
   * @param {string} salaryMonth - Filter by salary month (YYYY-MM-DD)
   * @param {number} page - Page number
   * @param {number} pageSize - Items per page
   */
  getSalaries: (employeeId = null, salaryMonth = null, page = 1, pageSize = 10) => {
    return api.get('/payroll/salaries', {
      params: {
        employee_id: employeeId,
        salary_month: salaryMonth,
        page,
        page_size: pageSize,
      },
    });
  },

  /**
   * Generate payroll records
   * @param {object} data - Payroll generation data
   */
  generatePayroll: (data) => {
    return api.post('/payroll/generate', data);
  },

  /**
   * Get attendance records
   * @param {number} employeeId - Filter by employee ID
   * @param {string} month - Filter by month
   */
  getAttendance: (employeeId = null, month = null) => {
    return api.get('/payroll/attendance', {
      params: {
        employee_id: employeeId,
        month,
      },
    });
  },

  /**
   * Get employee payroll profile
   * @param {number} employeeId - Employee ID
   */
  getPayrollProfile: (employeeId) => {
    return api.get(`/payroll/employee/${employeeId}/profile`);
  },
};

// ==================== Sync APIs ====================
export const syncAPI = {
  /**
   * Sync employees to payroll system
   * @param {array} employeeIds - Array of employee IDs to sync (null for all)
   */
  syncEmployees: (employeeIds = null) => {
    return api.post('/sync/employees', {
      employee_ids: employeeIds,
      sync_type: 'full',
    });
  },

  /**
   * Sync all data (departments, positions, employees)
   */
  syncAll: () => {
    return api.post('/sync/all');
  },

  /**
   * Validate if employee can be deleted
   * @param {number} employeeId - Employee ID
   */
  validateDeletion: (employeeId) => {
    return api.post('/sync/validate-deletion', {
      employee_id: employeeId,
    });
  },

  /**
   * Delete employee with validation
   * @param {number} employeeId - Employee ID
   * @param {boolean} forceDelete - Force delete without validation
   * @param {boolean} cascadeDelete - Also delete related payroll records
   */
  deleteEmployee: (employeeId, forceDelete = false, cascadeDelete = false) => {
    return api.post('/sync/delete-employee', {
      employee_id: employeeId,
      force_delete: forceDelete,
      cascade_delete: cascadeDelete,
    });
  },
};

// Export default api instance for custom requests
export default api;
